const body = $input.first().json.body || $input.first().json;

// Product data from WF02B
const product = {
  id:           body.product_id || `prod_${Date.now()}`,
  title:        body.title || 'Untitled Product',
  type:         body.product_type || 'planner',
  niche:        body.niche || 'productivity',
  description:  body.description || '',
  content:      body.content || {},  // structured content from WF02B
  price:        body.price || '9.99',
  brand:        'ClearStack Studio',
  tagline:      'Tools that clear your mind and build your future.',
  website:      'clearstackstudio.com',
  // Colors
  primary_color:   '#1B2A4A',
  accent_color:    '#C9A84C',
  text_color:      '#2C2C2C',
  light_bg:        '#F8F9FA',
  white:           '#FFFFFF'
};

// PDF layout templates by product type
const layouts = {
  weekly_planner: {
    pages: ['cover', 'welcome', 'yearly_overview', 'monthly_x3', 'weekly_x52', 'notes_x5'],
    orientation: 'portrait',
    size: 'A4'
  },
  daily_planner: {
    pages: ['cover', 'welcome', 'monthly_x12', 'daily_x365', 'notes_x10'],
    orientation: 'portrait',
    size: 'A4'
  },
  goal_tracker: {
    pages: ['cover', 'welcome', 'vision_board_template', 'quarterly_goals_x4', 'monthly_review_x12', 'weekly_checkin_x52', 'notes_x5'],
    orientation: 'portrait',
    size: 'A4'
  },
  habit_tracker: {
    pages: ['cover', 'welcome', 'monthly_habits_x12', 'weekly_habits_x52', 'progress_tracker', 'notes_x5'],
    orientation: 'portrait',
    size: 'A4'
  },
  client_tracker: {
    pages: ['cover', 'welcome', 'client_roster', 'project_tracker_x20', 'invoice_log', 'meeting_notes_x20'],
    orientation: 'portrait',
    size: 'A4'
  },
  content_calendar: {
    pages: ['cover', 'welcome', 'content_strategy', 'monthly_calendar_x12', 'post_planner_x52', 'analytics_tracker'],
    orientation: 'landscape',
    size: 'A4'
  },
  budget_planner: {
    pages: ['cover', 'welcome', 'yearly_budget', 'monthly_budget_x12', 'expense_tracker', 'savings_tracker'],
    orientation: 'portrait',
    size: 'A4'
  },
  generic: {
    pages: ['cover', 'welcome', 'main_x20', 'notes_x5'],
    orientation: 'portrait',
    size: 'A4'
  }
};

const layout = layouts[body.product_type] || layouts.generic;
const filename = `${product.id}_${product.title.toLowerCase().replace(/[^a-z0-9]+/g, '-').substring(0, 50)}.pdf`;

return [{ json: {
  product,
  layout,
  filename,
  output_path: `/tmp/pdf_gen/${filename}`,
  html_path: `/tmp/pdf_gen/${product.id}.html`,
  _ready: true
}}];

const raw = $input.first().json;
const config = $('⚙️ Prepare PDF Config').first().json;

let htmlData;
try {
  const content = raw?.message?.content || raw?.response || '';
  // Extract JSON - handle large responses
  const jsonMatch = content.match(/```json\n?([\s\S]*?)\n?```/);
  const rawJson = jsonMatch ? jsonMatch[1] : content;
  // Find the JSON object
  const objMatch = rawJson.match(/{[\s\S]*}/);
  htmlData = JSON.parse(objMatch ? objMatch[0] : rawJson);
} catch(e) {
  return [{ json: { error: true, message: `HTML parse failed: ${e.message}`, step: 'parse_html' } }];
}

if (!htmlData.html || htmlData.html.length < 500) {
  return [{ json: { error: true, message: 'HTML too short or missing', step: 'validate_html' } }];
}

// Post-process HTML: inject any missing wkhtmltopdf fixes
let html = htmlData.html;

// Ensure proper charset
if (!html.includes('charset')) {
  html = html.replace('<head>', '<head><meta charset="UTF-8">');
}

// Ensure viewport for wkhtmltopdf
if (!html.includes('@page')) {
  const pageRule = config.layout.orientation === 'landscape'
    ? '@page { size: A4 landscape; margin: 15mm; }'
    : '@page { size: A4 portrait; margin: 15mm; }';
  html = html.replace('<style>', `<style>\n${pageRule}\n`);
}

// Fix common wkhtmltopdf incompatibility: flexbox gap
html = html.replace(/gap:\s*[\d]+px/g, '');
html = html.replace(/column-gap:\s*[\d]+px/g, '');

return [{ json: {
  ...config,
  html_content: html,
  page_count: htmlData.page_count || 0,
  pages_breakdown: htmlData.pages_breakdown || [],
  design_notes: htmlData.design_notes || '',
  html_size_chars: html.length,
  _html_ready: true
}}];

const uploadOutput = $input.first().json.stdout || '';
const config = $('⚙️ Parse + Fix HTML for wkhtmltopdf').first().json;

// Parse upload results
const urlMatch = uploadOutput.match(/PUBLIC_URL=(.+)/);
const successMatch = uploadOutput.includes('UPLOAD_SUCCESS=true');
const fallbackMatch = uploadOutput.match(/FALLBACK_URL=(.+)/);

const pdfUrl = urlMatch ? urlMatch[1].trim() 
             : fallbackMatch ? fallbackMatch[1].trim()
             : null;

if (!pdfUrl) {
  return [{ json: { 
    error: true, 
    message: 'PDF URL not found in upload output',
    upload_output: uploadOutput
  }}];
}

const result = {
  product_id: config.product.id,
  product_title: config.product.title,
  product_type: config.product.type,
  pdf_url: pdfUrl,
  pdf_filename: config.filename,
  pdf_path: config.output_path,
  page_count: config.page_count,
  pages_breakdown: config.pages_breakdown,
  upload_method: successMatch ? 'cloudflare_r2' : 'local_nginx',
  generated_at: new Date().toISOString(),
  // Pass through for WF13 (mockup generation)
  _ready_for_mockup: true,
  _ready_for_publishing: true
};

console.log(`PDF ready: ${result.pdf_url}`);
return [{ json: result }];
